import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
  input,
  output,
} from '@angular/core';

/**
 * A smart component that demonstrates Compodoc integration with Storybook.
 */
@Component({
  selector: 'smart-ngx-smart-components',
  imports: [],
  template: `<p>{{ label() }}</p>`,
  styles: `
    :host {
      display: block;
    }
  `,
  encapsulation: ViewEncapsulation.Emulated,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class NgxSmartComponents {
  /** The label text displayed inside the component. */
  readonly label = input<string>('NgxSmartComponents works!');

  /** Emitted when the component is clicked. */
  readonly clicked = output<void>();
}

